import React, { useState, useEffect } from 'react';
import { Navbar, Container, Nav } from 'react-bootstrap';

function NavigationBar({ sections }) {
    const [navbarVisible, setNavbarVisible] = useState(true);

    useEffect(() => {
        let lastScrollTop = 0;

        const handleScroll = () => {
            const currentScrollTop = window.pageYOffset || document.documentElement.scrollTop;

            if (currentScrollTop > lastScrollTop) {
                // Scroll hacia abajo
                setNavbarVisible(false);
            } else {
                // Scroll hacia arriba
                setNavbarVisible(true);
            }
            
            lastScrollTop = currentScrollTop <= 0 ? 0 : currentScrollTop; // Para dispositivos móviles
        };

        window.addEventListener('scroll', handleScroll);
        
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    const handleClick = (sectionId) => {
        const section = document.getElementById(sectionId);
        if (section) {
            const navbarHeight = document.querySelector('.navbar').offsetHeight;
            const sectionPosition = section.offsetTop - navbarHeight;
            window.scrollTo({
                top: sectionPosition,
                behavior: 'smooth'
            });
        }
    };

    return (
        <Navbar collapseOnSelect expand="lg" bg="dark" variant="dark" className={navbarVisible ? 'show-navbar' : 'hide-navbar'}>
            <Container>
                <Navbar.Brand href="#home">Portfolio</Navbar.Brand>
                <Navbar.Toggle aria-controls="responsive-navbar-nav" />
                <Navbar.Collapse id="responsive-navbar-nav">
                    <Nav className="me-auto">
                        {sections.map((section, index) => (
                            <Nav.Link key={index} onClick={() => handleClick(section.id)}>
                                {section.text}
                            </Nav.Link>
                        ))}
                    </Nav>
                </Navbar.Collapse>
            </Container>
        </Navbar>
    );
}

export default NavigationBar;
